Еве пример за имплементација на алгоритмот за растојание Левенштајн во C++:

```
#include <iostream>
#include <алгоритам>
#include <string>

користејќи именски простор std;

int levenshtein_distance (низа s1, низа s2) {
    const int m = s1.size();
    const int n = s2.size();
    int dp[m + 1][n + 1];

    за (int i = 0; i <= m; i++) {
        dp[i][0] = i;
    }

    за (int j = 0; j <= n; j++) {
        dp[0][j] = j;
    }

    за (int i = 1; i <= m; i++) {
        за (int j = 1; j <= n; j++) {
            dp[i][j] = min({dp[i - 1][j] + 1, dp[i][j - 1] + 1, dp[i - 1][j - 1] + (s1[i - 1] != s2[j - 1])});
        }
    }

    враќање dp[m][n];
}

int main() {
    низа s1 = "маче";
    стринг s2 = "седи";
    cout << "Левенштајн растојание помеѓу " << s1 << " и " << s2 << " е " << levenshtein_distance(s1, s2) << endl;
    врати 0;
}
```

Оваа имплементација го пресметува растојанието Левенштајн помеѓу две влезни низи `s1` и `s2`. Прво ја иницијализира динамичната програмска табела `dp` со основните случаи за празни низи, а потоа ја пополнува табелата со повторување низ низите и споредување на секој пар знаци. Конечната вредност во табелата е минималното растојание на Левенштајн помеѓу двете жици.

